char* longestPalindrome(char* s) {
    int n = strlen(s);
    if (n < 2) return s;
    int bestL = 0, bestLen = 1;
    for (int i = 0; i < n; i++) {
        int l = i, r = i;
        while (l >= 0 && r < n && s[l] == s[r]) { l--; r++; }
        if (r - l - 1 > bestLen) { bestL = l + 1; bestLen = r - l - 1; }
        l = i; r = i + 1;
        while (l >= 0 && r < n && s[l] == s[r]) { l--; r++; }
        if (r - l - 1 > bestLen) { bestL = l + 1; bestLen = r - l - 1; }
    }
    char* res = (char*)malloc(bestLen + 1);
    strncpy(res, s + bestL, bestLen);
    res[bestLen] = '\0';
    return res;
}

